// Output 0: reminders, Output 1: summary
const threshold = $json[0].daysThreshold || 7;
const adminEmail = $json[0].adminEmail;
const now = Date.now();
const MS_IN_DAY = 86400000;

const reminders = [];

items.forEach(item => {
  const task = item.json;
  if (!task.due_date) return; // Skip tasks without due date
  const dueTs = Number(task.due_date);
  const daysLeft = Math.ceil((dueTs - now) / MS_IN_DAY);
  if (daysLeft <= threshold) {
    // Try to locate a custom field named "Email"
    const emailField = (task.custom_fields || []).find(f => f.name === 'Email');
    const customerEmail = emailField ? emailField.value : 'user@example.com';

    reminders.push({
      json: {
        taskId: task.id,
        subscriptionName: task.name,
        dueDateISO: new Date(dueTs).toISOString(),
        daysLeft,
        customerEmail,
        fromEmail: item.json.fromEmail,
        adminEmail,
        threshold
      }
    });
  }
});

const summary = [{
  json: {
    runAt: new Date().toISOString(),
    totalReminders: reminders.length,
    adminEmail,
    threshold
  }
}];

return [reminders, summary];

const total = $json.totalReminders;
const threshold = $json.threshold;
const runAt = $json.runAt;

const html = `<p>Hi Team,</p>
<p>${total} renewal reminder(s) were sent during the latest run (threshold: ${threshold} days).</p>
<p>Run time: ${runAt}</p>
<p>Regards,<br>n8n Bot</p>`;

return [{
  json: {
    adminEmail: $json.adminEmail,
    fromEmail: $json.fromEmail || 'user@example.com',
    summarySubject: `${total} subscription reminder(s) sent`,
    summaryHtml: html
  }
}];
